// omp/lud_omp.c
#include <stdio.h>
#include <omp.h>
#include "common.h"

#define BLOCK_SIZE 16

void lud_diagonal(float *m, int matrix_dim, int offset) {
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    int array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        shadow[i][0] = m[array_offset];
        array_offset += matrix_dim;
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = 0;
            for (int k = 0; k < i; k++) {
                sum += shadow[k][i] * shadow[j][k];
            }
            shadow[j][i] = (shadow[j][i] - sum) / shadow[i][i];
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        m[array_offset] = shadow[i][0];
        array_offset += matrix_dim;
    }
}

void lud_perimeter(float *m, int matrix_dim, int offset) {
    int i, j;
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        dia[i][0] = m[array_offset];
        array_offset += matrix_dim;
    }

    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        peri_row[i][0] = m[array_offset + BLOCK_SIZE];
        array_offset += matrix_dim;
    }

    array_offset = (offset + BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        peri_col[0][i] = m[array_offset];
        array_offset += matrix_dim;
    }

    #pragma omp parallel for
    for (i = 1; i < BLOCK_SIZE; i++) {
        float sum = 0;
        for (int j = 0; j < i; j++) {
            sum += dia[i][j] * peri_row[j][0];
        }
        peri_row[i][0] = peri_row[i][0] - sum;
    }

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        float sum = 0;
        for (int j = 0; j < i; j++) {
            sum += peri_col[0][j] * dia[j][i];
        }
        peri_col[0][i] = (peri_col[0][i] - sum) / dia[i][i];
    }

    array_offset = (offset + 1) * matrix_dim + offset + BLOCK_SIZE;
    for (i = 1; i < BLOCK_SIZE; i++) {
        m[array_offset] = peri_row[i][0];
        array_offset += matrix_dim;
    }

    array_offset = (offset + BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        m[array_offset] = peri_col[0][i];
        array_offset += matrix_dim;
    }
}

void lud_internal(float *m, int matrix_dim, int offset) {
    int i, j;
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int global_row_id = offset + BLOCK_SIZE;
    int global_col_id = offset + BLOCK_SIZE;

    int array_offset = (offset + 1) * matrix_dim + global_col_id;
    for (i = 0; i < BLOCK_SIZE; i++) {
        peri_row[i][0] = m[array_offset];
        array_offset += matrix_dim;
    }

    array_offset = global_row_id * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        peri_col[0][i] = m[array_offset];
        array_offset += matrix_dim;
    }

    #pragma omp parallel for
    for (i = 0; i < BLOCK_SIZE; i++) {
        float sum = 0;
        for (int j = 0; j < BLOCK_SIZE; j++) {
            sum += peri_col[0][j] * peri_row[j][i];
        }
        m[global_row_id * matrix_dim + global_col_id + i] -= sum;
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i;

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        lud_diagonal(m, matrix_dim, i);
        lud_perimeter(m, matrix_dim, i);
        #pragma omp parallel for
        for (int j = 0; j < (matrix_dim - i - BLOCK_SIZE) / BLOCK_SIZE; j++) {
            lud_internal(m, matrix_dim, i);
        }
    }
    lud_diagonal(m, matrix_dim, i);
}
